import 'package:equatable/equatable.dart';

import 'designation.dart';
import 'month.dart';
import 'weekday.dart';

class Gregorian extends Equatable {
  final String? date;
  final String? format;
  final String? day;
  final Weekday? weekday;
  final Month? month;
  final String? year;
  final Designation? designation;
  final bool? lunarSighting;

  const Gregorian({
    this.date,
    this.format,
    this.day,
    this.weekday,
    this.month,
    this.year,
    this.designation,
    this.lunarSighting,
  });

  factory Gregorian.(
    Map<String, dynamic> json,
  ) {
    return Gregorian(
      date: json['date'] as String?,
      format: json['format'] as String?,
      day: json['day'] as String?,
      weekday: json['weekday'] == null
          ? null
          : Weekday.(
              json['weekday'] as Map<String, dynamic>,
            ),
      month: json['month'] == null
          ? null
          : Month.(
              json['month'] as Map<String, dynamic>,
            ),
      year: json['year'] as String?,
      designation: json['designation'] == null
          ? null
          : Designation.(
              json['designation'] as Map<String, dynamic>,
            ),
      lunarSighting: json['lunarSighting'] as bool?,
    );
  }

  Map<String, dynamic>
  () {
    return {
      'date': date,
      'format': format,
      'day': day,
      'weekday': weekday
          ?.(),
      'month': month
          ?.(),
      'year': year,
      'designation': designation
          ?.(),
      'lunarSighting': lunarSighting,
    };
  }

  @override
  List<Object?> get props {
    return [
      date,
      format,
      day,
      weekday,
      month,
      year,
      designation,
      lunarSighting,
    ];
  }
}
